function Modal({ onClose, children, width=480 }) {
  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(10,20,30,0.65)", zIndex:500, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }} onClick={onClose}>
      <div style={{ background:C.blanco, borderRadius:18, padding:32, width:"100%", maxWidth:width, boxShadow:"0 24px 72px rgba(0,0,0,0.35)" }} onClick={e=>e.stopPropagation()}>
        {children}
      </div>
    </div>
  );
}

