/* ── Botón de sincronización manual ── */
function SyncButton({ proyectos }) {
  const [estado, setEstado] = useState("idle"); // idle | syncing | ok | error

  const sincronizar = async () => {
    setEstado("syncing");
    try {
      await sbSet("proyectos-v1", proyectos);
      setEstado("ok");
      setTimeout(() => setEstado("idle"), 3000);
    } catch(e) {
      setEstado("error");
      setTimeout(() => setEstado("idle"), 3000);
    }
  };

  const labels = {
    idle: "☁ Sincronizar",
    syncing: "⏳ Sincronizando...",
    ok: "✓ Sincronizado",
    error: "✕ Error",
  };
  const colors = {
    idle: "rgba(255,255,255,0.15)",
    syncing: "#E8A020",
    ok: C.verde,
    error: "#E74C3C",
  };

  return (
    <button onClick={sincronizar} disabled={estado==="syncing"} style={{
      padding:"6px 14px", borderRadius:6, border:"none",
      background: colors[estado], color:"#fff",
      fontSize:12, fontWeight:600, cursor: estado==="syncing"?"not-allowed":"pointer",
      transition:"all 0.3s"
    }}>
      {labels[estado]}
    </button>
  );
}

/* ═══════════════════════════════════════════
   ROOT
═══════════════════════════════════════════ */
export default function App() {
  const [logueado, setLogueado] = useState(false);
  const [proyectos, setProyectos] = useState([]);
  const [cargando, setCargando] = useState(true);
  const [proyectoActivo, setProyectoActivo] = useState(null);
  const [diagActivo, setDiagActivo] = useState(null); // {diag, esNuevo}
  const [dims, setDims] = useState(DIMS_BASE);
  const [showBackup, setShowBackup] = useState(false);
  const [importError, setImportError] = useState("");
  const [syncStatus, setSyncStatus] = useState("ok"); // "ok" | "saving" | "error"
  const [syncError, setSyncError] = useState("");
  const [showPapelera, setShowPapelera] = useState(false);
  const [papelera, setPapelera] = useState(() => {
    try { return JSON.parse(localStorage.getItem("papelera-v1") || "[]"); } catch(e) { return []; }
  });

  useEffect(()=>{
    (async()=>{
      try {
        // Cargar desde Supabase Y localStorage, luego hacer merge
        const [data, local] = await Promise.all([
          sbGet("proyectos-v1").catch(() => null),
          Promise.resolve(localStorage.getItem("proyectos-v1"))
        ]);
        const sbData  = data && Array.isArray(data) ? data : null;
        const lcData  = local ? JSON.parse(local) : null;

        if (sbData && lcData) {
          // MERGE: no perder diagnósticos que están solo en localStorage
          const sbDiagIds = new Set();
          sbData.forEach(p => (p.diagnosticos||[]).forEach(d => sbDiagIds.add(p.id+"::"+d.id)));
          let huboCambios = false;
          const merged = sbData.map(prog => {
            const lcProg = lcData.find(lp => lp.id === prog.id);
            if (!lcProg) return prog;
            const soloLocales = (lcProg.diagnosticos||[]).filter(d => !sbDiagIds.has(prog.id+"::"+d.id));
            if (soloLocales.length > 0) {
              huboCambios = true;
              return {...prog, diagnosticos:[...(prog.diagnosticos||[]), ...soloLocales]};
            }
            return prog;
          });
          setProyectos(merged);
          localStorage.setItem("proyectos-v1", JSON.stringify(merged));
          if (huboCambios) {
            // Subir a Supabase los datos locales recuperados
            sbSet("proyectos-v1", merged).catch(console.error);
          }
        } else if (sbData) {
          setProyectos(sbData);
          localStorage.setItem("proyectos-v1", JSON.stringify(sbData));
        } else if (lcData) {
          setProyectos(lcData);
          sbSet("proyectos-v1", lcData).catch(console.error);
        }
      } catch(_) {
        try {
          const local = localStorage.getItem("proyectos-v1");
          if (local) setProyectos(JSON.parse(local));
        } catch(__) {}
      }
      setCargando(false);
    })();
  },[]);

  // Migración: limpiar _borrador:true de diagnósticos que sí tienen fechaGuardado
  useEffect(() => {
    if (proyectos.length === 0) return;
    let huboFix = false;
    const fixed = proyectos.map(p => ({
      ...p,
      diagnosticos: (p.diagnosticos||[]).map(d => {
        // Si tiene _borrador:true pero ya tiene fechaGuardado o fechaInicial → ya fue guardado
        if (d._borrador && (d.fechaGuardado || d.fechaInicial)) {
          huboFix = true;
          return { ...d, _borrador: false };
        }
        return d;
      })
    }));
    if (huboFix) {
      setProyectos(fixed);
      try { localStorage.setItem("proyectos-v1", JSON.stringify(fixed)); } catch(_){}
      sbSet("proyectos-v1", fixed).catch(console.error);
    }
  }, [proyectos.length]);


  const saveProyectos = async (lista) => {
    setProyectos(lista);
    // Guardar localmente primero — instantáneo
    try { localStorage.setItem("proyectos-v1", JSON.stringify(lista)); } catch(_){}
    // Sincronizar con Supabase con indicador y reintento
    setSyncStatus("saving");
    const intentarSync = async (intentos=0) => {
      try {
        await sbSet("proyectos-v1", lista);
        setSyncStatus("ok");
        setSyncError("");
      } catch(e) {
        if (intentos < 2) {
          // Reintentar hasta 2 veces con delay
          setTimeout(() => intentarSync(intentos+1), 2000);
        } else {
          setSyncStatus("error");
          setSyncError("No se pudo sincronizar con el servidor. Los datos están guardados localmente, pero no estarán disponibles desde otros dispositivos hasta que se restaure la conexión.");
          console.error("sbSet falló tras 3 intentos:", e);
        }
      }
    };
    intentarSync();
  };

  const guardarEnPapelera = (item) => {
    const entrada = { ...item, _eliminadoEn: new Date().toISOString() };
    const nueva = [entrada, ...papelera].slice(0, 100); // máximo 100 ítems
    setPapelera(nueva);
    try { localStorage.setItem("papelera-v1", JSON.stringify(nueva)); } catch(e) {}
  };

  const crearPrograma = (p) => saveProyectos([...proyectos,{...p,diagnosticos:[]}]);
  const editarPrograma = (p) => saveProyectos(proyectos.map(x=>x.id===p.id?{...x,...p,diagnosticos:x.diagnosticos}:x));
  const eliminarPrograma = (id) => {
    const prog = proyectos.find(p=>p.id===id);
    if (prog) guardarEnPapelera({ tipo:"programa", programa: prog });
    saveProyectos(proyectos.filter(p=>p.id!==id));
  };
  const eliminarDiag = (diagId) => {
    const diag = (proyectoActivo?.diagnosticos||[]).find(d=>d.id===diagId);
    if (diag) guardarEnPapelera({ tipo:"diagnostico", diagnostico: diag, programaId: proyectoActivo.id, programaNombre: proyectoActivo.nombre });
    const updated = proyectos.map(p=>p.id===proyectoActivo.id?{...p,diagnosticos:(p.diagnosticos||[]).filter(d=>d.id!==diagId)}:p);
    saveProyectos(updated);
    setProyectoActivo(updated.find(p=>p.id===proyectoActivo.id));
  };
  const guardarDiag = (rec) => {
    // Si el id termina en _final_new, es un diagnóstico final nuevo — quitar el sufijo
    const recFinal = rec.id.endsWith("_final_new")
      ? {...rec, id: rec.id.replace("_final_new","")+"_final"}
      : rec;
    const updated = proyectos.map(p=>{
      if(p.id!==proyectoActivo.id) return p;
      const existe = (p.diagnosticos||[]).some(d=>d.id===recFinal.id);
      const diags = existe
        ? (p.diagnosticos||[]).map(d=>d.id===recFinal.id?recFinal:d)
        : [...(p.diagnosticos||[]),recFinal];
      return {...p,diagnosticos:diags};
    });
    saveProyectos(updated);
    setProyectoActivo(updated.find(p=>p.id===proyectoActivo.id));
    setDiagActivo({diag:recFinal,esNuevo:false});
  };

  const exportarBackup = () => {
    try {
      const backup = { version:"1.0", fecha:new Date().toISOString(), proyectos };
      const json = JSON.stringify(backup, null, 2);
      const dataUri = "data:application/json;charset=utf-8," + encodeURIComponent(json);
      const a = document.createElement("a");
      a.href = dataUri;
      a.download = "backup-cidere-" + new Date().toLocaleDateString("es-CL").replace(/\//g,"-") + ".json";
      a.click();
    } catch(err) {
      alert("Error al exportar: " + err.message);
    }
  };

  const importarBackup = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      try {
        const data = JSON.parse(ev.target.result);
        if (!data.proyectos || !Array.isArray(data.proyectos)) throw new Error("Formato inválido");
        // Guardar localmente primero — nunca bloquea
        const lista = data.proyectos;
        setProyectos(lista);
        try { localStorage.setItem("proyectos-v1", JSON.stringify(lista)); } catch(_){}
        // Sincronizar Supabase en background sin bloquear
        sbSet("proyectos-v1", lista).catch(()=>{});
        setShowBackup(false);
        setImportError("");
        alert("✓ Backup restaurado. " + lista.length + " programa(s) importado(s).");
      } catch(err) {
        setImportError("Archivo inválido. Asegúrate de importar un backup exportado desde esta aplicación.");
      }
    };
    reader.onerror = () => setImportError("No se pudo leer el archivo.");
    reader.readAsText(file);
    e.target.value = "";
  };

  const restaurarDePapelera = (idx) => {
    const item = papelera[idx];
    if (!item) return;
    if (item.tipo === "programa") {
      const yaExiste = proyectos.some(p=>p.id===item.programa.id);
      if (yaExiste) { alert("Ya existe un programa con ese ID. Renombra el actual antes de restaurar."); return; }
      saveProyectos([...proyectos, item.programa]);
    } else if (item.tipo === "diagnostico") {
      const prog = proyectos.find(p=>p.id===item.programaId);
      if (!prog) { alert(`El programa "${item.programaNombre}" ya no existe. Restáuralo primero.`); return; }
      const updated = proyectos.map(p=>p.id===item.programaId
        ? {...p, diagnosticos:[...(p.diagnosticos||[]).filter(d=>d.id!==item.diagnostico.id), item.diagnostico]}
        : p);
      saveProyectos(updated);
      if (proyectoActivo?.id===item.programaId) setProyectoActivo(updated.find(p=>p.id===item.programaId));
    }
    const nueva = papelera.filter((_,i)=>i!==idx);
    setPapelera(nueva);
    try { localStorage.setItem("papelera-v1", JSON.stringify(nueva)); } catch(e) {}
    alert("✓ Restaurado correctamente.");
  };

  const vaciarPapelera = () => {
    if (!window.confirm("¿Vaciar la papelera permanentemente? Esta acción no se puede deshacer.")) return;
    setPapelera([]);
    try { localStorage.removeItem("papelera-v1"); } catch(e) {}
  };

  if(!logueado) return <PantallaLogin onOk={()=>setLogueado(true)}/>;
  if(cargando) return <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",background:C.fondo,color:C.gris}}>Cargando…</div>;

  return (
    <div style={{ minHeight:"100vh",display:"flex",flexDirection:"column",background:C.fondo,fontFamily:"'Segoe UI',system-ui,sans-serif",color:C.oscuro }}>
      {/* HEADER OSCURO */}
      <div style={{ background:C.headerBg,borderBottom:`1px solid ${C.headerBd}`,padding:"0 24px",height:84,display:"flex",alignItems:"center",justifyContent:"space-between",flexShrink:0,position:"sticky",top:0,zIndex:200 }}>
        <div style={{ display:"flex",alignItems:"center",gap:16,cursor:"pointer" }} onClick={()=>{setProyectoActivo(null);setDiagActivo(null);}}>
          <LogoCidere height={70} />
          {proyectoActivo && (
            <>
              <span style={{ color:"rgba(255,255,255,0.25)",fontSize:18 }}>›</span>
              {proyectoActivo.logoUrl && (
                <>
                  <div style={{ width:1, height:24, background:"rgba(255,255,255,0.2)" }}/>
                  <img src={proyectoActivo.logoUrl} alt={proyectoActivo.nombre} style={{ height:28, objectFit:"contain", background:"rgba(255,255,255,0.92)", borderRadius:6, padding:"2px 8px" }}/>
                </>
              )}
              <span style={{ fontSize:13,fontWeight:700,color:"rgba(255,255,255,0.85)" }}>{proyectoActivo.nombre}</span>
              {diagActivo && (
                <>
                  <span style={{ color:"rgba(255,255,255,0.25)",fontSize:18 }}>›</span>
                  <span style={{ fontSize:12,color:"rgba(255,255,255,0.55)" }}>{diagActivo.diag?.infoGeneral?.empresa||"Nuevo diagnóstico"}</span>
                </>
              )}
            </>
          )}
        </div>
        <div style={{ display:"flex",alignItems:"center",gap:10 }}>
          {/* Indicador de sincronización */}
          {syncStatus==="saving" && (
            <div style={{display:"flex",alignItems:"center",gap:6,padding:"5px 11px",background:"rgba(255,255,255,0.08)",borderRadius:8,fontSize:11,color:"rgba(255,255,255,0.65)"}}>
              <div style={{width:7,height:7,borderRadius:"50%",background:"#F0C040"}}/>
              Guardando…
            </div>
          )}
          {syncStatus==="ok" && (
            <div style={{display:"flex",alignItems:"center",gap:6,padding:"5px 11px",background:"rgba(255,255,255,0.05)",borderRadius:8,fontSize:11,color:"rgba(255,255,255,0.4)"}}>
              <div style={{width:7,height:7,borderRadius:"50%",background:"#3BAD8A"}}/>
              Sincronizado
            </div>
          )}
          {syncStatus==="error" && (
            <div title={syncError} style={{display:"flex",alignItems:"center",gap:6,padding:"5px 11px",background:"rgba(231,76,60,0.2)",border:"1px solid rgba(231,76,60,0.35)",borderRadius:8,fontSize:11,color:"#FF8A80",cursor:"help"}}>
              <div style={{width:7,height:7,borderRadius:"50%",background:"#E74C3C"}}/>
              ⚠ Sin sincronizar
            </div>
          )}
          <button onClick={()=>setShowPapelera(true)} style={{ padding:"7px 14px",background:"rgba(255,255,255,0.08)",border:"1px solid rgba(255,255,255,0.15)",borderRadius:8,color:"rgba(255,255,255,0.8)",fontSize:12,cursor:"pointer",fontWeight:600,position:"relative" }}>
            🗑 Papelera{papelera.length>0?<span style={{position:"absolute",top:-5,right:-5,background:"#E74C3C",color:"#fff",borderRadius:"50%",width:16,height:16,fontSize:9,display:"flex",alignItems:"center",justifyContent:"center",fontWeight:800}}>{papelera.length}</span>:null}
          </button>
          <button onClick={()=>{setShowBackup(true);setImportError("");}} style={{ padding:"7px 14px",background:"rgba(255,255,255,0.08)",border:"1px solid rgba(255,255,255,0.15)",borderRadius:8,color:"rgba(255,255,255,0.8)",fontSize:12,cursor:"pointer",fontWeight:600 }}>💾 Backup</button>
          <div style={{ width:30,height:30,borderRadius:"50%",background:`linear-gradient(135deg,${C.verde},${C.azul})`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:13,fontWeight:700,color:"#fff" }}>C</div>
        </div>
        {showPapelera && (
          <div style={{position:"fixed",inset:0,background:"rgba(10,20,30,0.75)",zIndex:1000,display:"flex",alignItems:"center",justifyContent:"center",padding:16}} onClick={()=>setShowPapelera(false)}>
            <div style={{background:"#fff",borderRadius:16,padding:0,width:"100%",maxWidth:620,maxHeight:"80vh",boxShadow:"0 24px 72px rgba(0,0,0,0.3)",display:"flex",flexDirection:"column",overflow:"hidden"}} onClick={e=>e.stopPropagation()}>
              {/* Header */}
              <div style={{padding:"18px 24px",borderBottom:"1px solid #EEF3F8",display:"flex",justifyContent:"space-between",alignItems:"center",flexShrink:0}}>
                <div>
                  <h2 style={{fontSize:18,fontWeight:800,color:"#1C2B3A",margin:0}}>🗑 Papelera</h2>
                  <p style={{fontSize:12,color:"#637D92",margin:"3px 0 0 0"}}>Aquí puedes recuperar diagnósticos o programas eliminados recientemente.</p>
                </div>
                <div style={{display:"flex",gap:8}}>
                  {papelera.length>0 && <button onClick={vaciarPapelera} style={{padding:"7px 12px",border:"1px solid #fcc",borderRadius:8,background:"#fff5f5",color:"#E74C3C",fontSize:12,cursor:"pointer",fontWeight:600}}>Vaciar papelera</button>}
                  <button onClick={()=>setShowPapelera(false)} style={{padding:"7px 12px",border:"1px solid #DDE6EF",borderRadius:8,background:"transparent",color:"#637D92",fontSize:12,cursor:"pointer"}}>Cerrar</button>
                </div>
              </div>
              {/* Lista */}
              <div style={{overflowY:"auto",flex:1,padding:"12px 16px"}}>
                {papelera.length===0 ? (
                  <div style={{textAlign:"center",padding:"40px 20px",color:"#A0B0C0"}}>
                    <div style={{fontSize:40,marginBottom:10}}>🗑</div>
                    <div style={{fontSize:14,fontWeight:600}}>La papelera está vacía</div>
                    <div style={{fontSize:12,marginTop:4}}>Los diagnósticos y programas eliminados aparecerán aquí</div>
                  </div>
                ) : papelera.map((item,idx) => {
                  const esDiag = item.tipo==="diagnostico";
                  const nombre = esDiag ? (item.diagnostico?.infoGeneral?.empresa||"Sin nombre") : (item.programa?.nombre||"Sin nombre");
                  const subtitulo = esDiag ? `Diagnóstico ${item.diagnostico?.tipo==="salida"?"final":"inicial"} · ${item.programaNombre}` : `Programa · ${(item.programa?.diagnosticos||[]).length} diagnóstico(s)`;
                  const fecha = new Date(item._eliminadoEn).toLocaleDateString("es-CL",{day:"2-digit",month:"short",year:"numeric",hour:"2-digit",minute:"2-digit"});
                  return (
                    <div key={idx} style={{display:"flex",alignItems:"center",gap:12,padding:"12px 14px",background:"#FAFBFC",borderRadius:10,marginBottom:8,border:"1px solid #EEF3F8"}}>
                      <div style={{width:40,height:40,borderRadius:10,background:esDiag?"#EAF1FA":"#F0EAF7",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,flexShrink:0}}>
                        {esDiag?"📋":"📁"}
                      </div>
                      <div style={{flex:1,minWidth:0}}>
                        <div style={{fontSize:13,fontWeight:700,color:"#1C2B3A",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{nombre}</div>
                        <div style={{fontSize:11,color:"#637D92",marginTop:2}}>{subtitulo}</div>
                        <div style={{fontSize:10,color:"#A0B0C0",marginTop:2}}>Eliminado el {fecha}</div>
                      </div>
                      <button onClick={()=>restaurarDePapelera(idx)} style={{padding:"8px 14px",background:"linear-gradient(135deg,#3BAD8A,#2A9070)",border:"none",borderRadius:8,color:"#fff",fontSize:12,fontWeight:700,cursor:"pointer",flexShrink:0}}>
                        ↩ Restaurar
                      </button>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        )}
        {showBackup && (
          <div style={{position:"fixed",inset:0,background:"rgba(10,20,30,0.75)",zIndex:1000,display:"flex",alignItems:"center",justifyContent:"center",padding:16}} onClick={()=>setShowBackup(false)}>
            <div style={{background:"#fff",borderRadius:16,padding:28,width:"100%",maxWidth:420,boxShadow:"0 24px 72px rgba(0,0,0,0.3)"}} onClick={e=>e.stopPropagation()}>
              <div style={{fontSize:11,color:"#637D92",textTransform:"uppercase",letterSpacing:1,marginBottom:4}}>Gestión de datos</div>
              <h2 style={{fontSize:18,fontWeight:800,color:"#1C2B3A",margin:"0 0 6px 0"}}>Backup</h2>
              <p style={{fontSize:13,color:"#637D92",margin:"0 0 20px 0"}}>Exporta toda la información como respaldo, o importa un backup previo para restaurar tus datos.</p>
              <div style={{display:"flex",flexDirection:"column",gap:10}}>
                <button onClick={exportarBackup} style={{padding:"12px 16px",background:"linear-gradient(135deg,#2B7BBF,#1A5A9A)",border:"none",borderRadius:10,color:"#fff",fontSize:14,fontWeight:700,cursor:"pointer",textAlign:"left"}}>
                  ⬇ Exportar backup
                  <div style={{fontSize:11,fontWeight:400,opacity:0.8,marginTop:2}}>Descarga un archivo .json con todos tus programas y diagnósticos</div>
                </button>
                <label style={{padding:"12px 16px",background:"#F5F7FA",border:"2px dashed #DDE6EF",borderRadius:10,color:"#1C2B3A",fontSize:14,fontWeight:700,cursor:"pointer",display:"block"}}>
                  ⬆ Importar backup
                  <div style={{fontSize:11,fontWeight:400,color:"#637D92",marginTop:2}}>Selecciona un archivo .json exportado anteriormente</div>
                  <input type="file" accept=".json" style={{display:"none"}} onChange={importarBackup}/>
                </label>
                {importError && <div style={{padding:"10px 14px",background:"#FFF0F0",border:"1px solid #fcc",borderRadius:8,color:"#E74C3C",fontSize:12}}>{importError}</div>}
              </div>
              <button onClick={()=>setShowBackup(false)} style={{marginTop:16,width:"100%",padding:"10px",border:"1px solid #DDE6EF",borderRadius:8,background:"transparent",color:"#637D92",cursor:"pointer",fontSize:13}}>Cerrar</button>
            </div>
          </div>
        )}
      </div>

      {/* BODY */}
      <div style={{ flex:1,display:"flex",minHeight:0,position:"relative" }}>
        {!proyectoActivo && (
          <PantallaProyectos proyectos={proyectos} onSeleccionar={p=>{setProyectoActivo(p);setDiagActivo(null);}} onCrear={crearPrograma} onEditar={editarPrograma} onEliminar={eliminarPrograma}/>
        )}
        {proyectoActivo && !diagActivo && (
          <VistaPrograma programa={proyectoActivo} dims={dims} onNuevoDiag={()=>setDiagActivo({diag:null,esNuevo:true})} onAbrirDiag={d=>setDiagActivo({diag:d,esNuevo:false})} onEliminarDiag={eliminarDiag} onVolver={()=>{setProyectoActivo(null);setDiagActivo(null);}}/>
        )}
        {proyectoActivo && diagActivo && (
          <FormDiagnostico dims={dims} diagActual={diagActivo.diag} programa={proyectoActivo} onGuardar={guardarDiag} onVolver={()=>setDiagActivo(null)}/>
        )}
      </div>
    </div>
  );
}
